mapper.select:
SELECT s.*, (SELECT IFNULL(SUM(payment_price), 0) FROM PAYMENT p WHERE p.status = '결제완료' AND (CASE WHEN s.target_type = 'GYM' THEN p.gym_id ELSE p.trainer_id END) = s.target_id AND DATE_FORMAT(p.payment_date, '%Y-%m') = s.settlement_month ) as total_sales, (SELECT IFNULL(SUM(payment_fee), 0) FROM PAYMENT p WHERE p.status = '결제완료' AND (CASE WHEN s.target_type = 'GYM' THEN p.gym_id ELSE p.trainer_id END) = s.target_id AND DATE_FORMAT(p.payment_date, '%Y-%m') = s.settlement_month ) as total_fee, (SELECT IFNULL(SUM(payment_price) - SUM(payment_fee), 0) FROM PAYMENT p WHERE p.status = '결제완료' AND (CASE WHEN s.target_type = 'GYM' THEN p.gym_id ELSE p.trainer_id END) = s.target_id AND DATE_FORMAT(p.payment_date, '%Y-%m') = s.settlement_month ) as total_amount FROM SETTLEMENT s
AND s.status = #{status}
AND (s.target_id LIKE CONCAT('%', #{searchKeyword}, '%'))
ORDER BY s.settlement_deadline ASC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM SETTLEMENT s


		AND s.status = #{status}


		AND (s.target_id LIKE CONCAT('%', #{searchKeyword}, '%'))

SELECT p.id, p.payment_date, p.payment_price, p.payment_fee, (p.payment_price-p.payment_fee) as payment_amount, p.gym_id, g.name as gym_name, p.trainer_id, u.name as trainer_name FROM PAYMENT p LEFT JOIN GYM g ON p.gym_id = g.id LEFT JOIN TRAINER t ON p.trainer_id = t.id LEFT JOIN USER u ON t.user_id = u.id WHERE p.status = '결제완료'
AND p.payment_date BETWEEN #{startDate} AND #{endDate}
AND p.gym_id IS NOT NULL AND p.trainer_id IS NULL
AND p.trainer_id IS NOT NULL
AND (g.name LIKE CONCAT('%', #{salesSearch}, '%') OR u.name LIKE CONCAT('%', #{salesSearch}, '%'))
ORDER BY p.payment_date DESC LIMIT #{pageSize} OFFSET #{salesOffset}

    SELECT p.*, u.name as user_name 
    FROM PAYMENT p
    LEFT JOIN USER u ON p.user_id = u.id



        AND p.payment_date BETWEEN #{startDate} AND #{endDate}



        AND p.status = #{status}



        AND (u.name LIKE CONCAT('%', #{paymentSearch}, '%') OR p.id LIKE CONCAT('%', #{paymentSearch}, '%'))


ORDER BY p.payment_date DESC
LIMIT #{pageSize} OFFSET #{paymentOffset}

SELECT COUNT(*)
FROM PAYMENT p
LEFT JOIN USER u ON p.user_id = u.id


    AND p.payment_date BETWEEN #{startDate} AND #{endDate}


    AND p.status = #{status}


    AND (u.name LIKE CONCAT('%', #{paymentSearch}, '%') OR p.id LIKE CONCAT('%', #{paymentSearch}, '%'))
